from __future__ import annotations

BUILDING_REGS_FAQS = [{'question': 'Are building regulations the same as planning permission?', 'answer': 'No. Planning permission is about whether development is acceptable in planning terms. Building regulations are about technical standards such as structure, fire safety, drainage, ventilation, energy performance and safe installation work. A project can need both.', 'source_ids': ['govuk_building_regs_approval']}, {'question': 'Can permitted development still need building regulations approval?', 'answer': 'Yes. Permitted development only affects the planning route. Extensions, loft conversions, garage conversions and structural changes can still need building control even when planning permission is not needed.', 'source_ids': ['govuk_building_regs_approval']}, {'question': 'Who checks building regulations?', 'answer': 'For ordinary domestic work in England, building control is usually handled by a local authority building control service or a registered building control approver. Higher-risk buildings have a separate Building Safety Regulator route.', 'source_ids': ['govuk_how_to_apply', 'govuk_bsr_higher_risk_buildings']}, {'question': 'What is a competent person scheme?', 'answer': 'A competent person scheme lets registered tradespeople self-certify certain types of work, so the homeowner may not need to make a separate building-control application for that specific work.', 'source_ids': ['govuk_use_competent_person', 'govuk_competent_person_schemes']}, {'question': 'What proof should I keep?', 'answer': 'Keep the application reference, plans, structural calculations, inspection records, completion certificate and any installer certificates. These can matter later when selling, remortgaging or resolving disputes.', 'source_ids': ['govuk_how_to_apply']}, {'question': 'Is a building notice safer than full plans?', 'answer': 'It is usually faster and lighter on upfront plans, but it gives less certainty before work starts. More complex work is often better suited to full plans or early professional advice.', 'source_ids': ['planning_portal_building_notice']}, {'question': 'Can I regularise old work?', 'answer': 'Some work may be handled through a regularisation route, but it depends on the work, timing, evidence and the building control body. Gather plans, photos, invoices and any certificates before asking.', 'source_ids': ['govuk_how_to_apply']}, {'question': 'Does Scotland use the same route?', 'answer': 'No. Scotland uses its own building standards and building warrant system. England-first pages should not be reused as Scottish guidance.', 'source_ids': ['govscot_domestic_technical_handbook_2026']}]
